            migrationBuilder.InsertData(
                table: "Documents",
                columns: new[] { "Id", "Conteudo", "Dificuldade", "LeituraMinutos", "Ordem", "Resumo", "Titulo", "TopicId" },
                values: new object[,]
                {
                    { 1, "\r\n<h2>Introdução à Farmacologia</h2>\r\n<p class='lead'>Conceitos fundamentais de farmacologia, definições de fármaco, droga e medicamento. Histórico e importância na prática clínica.</p>\r\n\r\n<h3>Introdução</h3>\r\n<p>Este documento aborda os conceitos fundamentais relacionados a <strong>introdução à farmacologia</strong>, um tema essencial para a formação do profissional farmacêutico. O domínio deste conteúdo é frequentemente cobrado em provas de concursos e residências farmacêuticas.</p>\r\n\r\n<h3>Conceitos Fundamentais</h3>\r\n<p>A compreensão aprofundada deste tema requer o conhecimento de princípios teóricos e sua aplicação na prática farmacêutica. Os principais pontos a serem estudados incluem definições, classificações, mecanismos e aplicações clínicas.</p>\r\n<ul>\r\n<li>Definições e terminologia técnica específica da área</li>\r\n<li>Classificação e categorização sistemática</li>\r\n<li>Mecanismos de ação e princípios fundamentais</li>\r\n<li>Aplicações práticas no contexto farmacêutico</li>\r\n<li>Correlações clínicas e relevância terapêutica</li>\r\n</ul>\r\n\r\n<h3>Aspectos Práticos</h3>\r\n<p>Na prática profissional, o farmacêutico deve ser capaz de aplicar estes conhecimentos para tomada de decisões clínicas, orientação de pacientes e garantia da qualidade dos serviços prestados.</p>\r\n\r\n<h3>Pontos-Chave para Revisão</h3>\r\n<ul>\r\n<li>Dominar os conceitos teóricos fundamentais</li>\r\n<li>Compreender as aplicações clínicas e práticas</li>\r\n<li>Conhecer a legislação e normas relacionadas</li>\r\n<li>Relacionar com outras disciplinas da formação farmacêutica</li>\r\n</ul>\r\n", "Básico", 8, 1, "Conceitos fundamentais de farmacologia, definições de fármaco, droga e medicamento. Histórico e importância na prática clínica.", "Introdução à Farmacologia", 1 },
                    { 2, "\r\n<h2>Farmacocinética: Absorção</h2>\r\n<p class='lead'>Mecanismos de absorção de fármacos, biodisponibilidade, fatores que influenciam a absorção e vias de administração.</p>\r\n\r\n<h3>Introdução</h3>\r\n<p>Este documento aborda os conceitos fundamentais relacionados a <strong>farmacocinética: absorção</strong>, um tema essencial para a formação do profissional farmacêutico. O domínio deste conteúdo é frequentemente cobrado em provas de concursos e residências farmacêuticas.</p>\r\n\r\n<h3>Conceitos Fundamentais</h3>\r\n<p>A compreensão aprofundada deste tema requer o conhecimento de princípios teóricos e sua aplicação na prática farmacêutica. Os principais pontos a serem estudados incluem definições, classificações, mecanismos e aplicações clínicas.</p>\r\n<ul>\r\n<li>Definições e terminologia técnica específica da área</li>\r\n<li>Classificação e categorização sistemática</li>\r\n<li>Mecanismos de ação e princípios fundamentais</li>\r\n<li>Aplicações práticas no contexto farmacêutico</li>\r\n<li>Correlações clínicas e relevância terapêutica</li>\r\n</ul>\r\n\r\n<h3>Aspectos Práticos</h3>\r\n<p>Na prática profissional, o farmacêutico deve ser capaz de aplicar estes conhecimentos para tomada de decisões clínicas, orientação de pacientes e garantia da qualidade dos serviços prestados.</p>\r\n\r\n<h3>Pontos-Chave para Revisão</h3>\r\n<ul>\r\n<li>Dominar os conceitos teóricos fundamentais</li>\r\n<li>Compreender as aplicações clínicas e práticas</li>\r\n<li>Conhecer a legislação e normas relacionadas</li>\r\n<li>Relacionar com outras disciplinas da formação farmacêutica</li>\r\n</ul>\r\n", "Intermediário", 10, 2, "Mecanismos de absorção de fármacos, biodisponibilidade, fatores que influenciam a absorção e vias de administração.", "Farmacocinética: Absorção", 1 },
                    { 3, "\r\n<h2>Farmacocinética: Distribuição</h2>\r\n<p class='lead'>Distribuição de fármacos nos tecidos, ligação a proteínas plasmáticas, volume de distribuição e barreiras biológicas.</p>\r\n\r\n<h3>Introdução</h3>\r\n<p>Este documento aborda os conceitos fundamentais relacionados a <strong>farmacocinética: distribuição</strong>, um tema essencial para a formação do profissional farmacêutico. O domínio deste conteúdo é frequentemente cobrado em provas de concursos e residências farmacêuticas.</p>\r\n\r\n<h3>Conceitos Fundamentais</h3>\r\n<p>A compreensão aprofundada deste tema requer o conhecimento de princípios teóricos e sua aplicação na prática farmacêutica. Os principais pontos a serem estudados incluem definições, classificações, mecanismos e aplicações clínicas.</p>\r\n<ul>\r\n<li>Definições e terminologia técnica específica da área</li>\r\n<li>Classificação e categorização sistemática</li>\r\n<li>Mecanismos de ação e princípios fundamentais</li>\r\n<li>Aplicações práticas no contexto farmacêutico</li>\r\n<li>Correlações clínicas e relevância terapêutica</li>\r\n</ul>\r\n\r\n<h3>Aspectos Práticos</h3>\r\n<p>Na prática profissional, o farmacêutico deve ser capaz de aplicar estes conhecimentos para tomada de decisões clínicas, orientação de pacientes e garantia da qualidade dos serviços prestados.</p>\r\n\r\n<h3>Pontos-Chave para Revisão</h3>\r\n<ul>\r\n<li>Dominar os conceitos teóricos fundamentais</li>\r\n<li>Compreender as aplicações clínicas e práticas</li>\r\n<li>Conhecer a legislação e normas relacionadas</li>\r\n<li>Relacionar com outras disciplinas da formação farmacêutica</li>\r\n</ul>\r\n", "Intermediário", 10, 3, "Distribuição de fármacos nos tecidos, ligação a proteínas plasmáticas, volume de distribuição e barreiras biológicas.", "Farmacocinética: Distribuição", 1 },
                    { 4, "\r\n<h2>Farmacocinética: Metabolismo</h2>\r\n<p class='lead'>Biotransformação hepática, reações de fase I e fase II, sistema CYP450, indução e inibição enzimática.</p>\r\n\r\n<h3>Introdução</h3>\r\n<p>Este documento aborda os conceitos fundamentais relacionados a <strong>farmacocinética: metabolismo</strong>, um tema essencial para a formação do profissional farmacêutico. O domínio deste conteúdo é frequentemente cobrado em provas de concursos e residências farmacêuticas.</p>\r\n\r\n<h3>Conceitos Fundamentais</h3>\r\n<p>A compreensão aprofundada deste tema requer o conhecimento de princípios teóricos e sua aplicação na prática farmacêutica. Os principais pontos a serem estudados incluem definições, classificações, mecanismos e aplicações clínicas.</p>\r\n<ul>\r\n<li>Definições e terminologia técnica específica da área</li>\r\n<li>Classificação e categorização sistemática</li>\r\n<li>Mecanismos de ação e princípios fundamentais</li>\r\n<li>Aplicações práticas no contexto farmacêutico</li>\r\n<li>Correlações clínicas e relevância terapêutica</li>\r\n</ul>\r\n\r\n<h3>Aspectos Práticos</h3>\r\n<p>Na prática profissional, o farmacêutico deve ser capaz de aplicar estes conhecimentos para tomada de decisões clínicas, orientação de pacientes e garantia da qualidade dos serviços prestados.</p>\r\n\r\n<h3>Pontos-Chave para Revisão</h3>\r\n<ul>\r\n<li>Dominar os conceitos teóricos fundamentais</li>\r\n<li>Compreender as aplicações clínicas e práticas</li>\r\n<li>Conhecer a legislação e normas relacionadas</li>\r\n<li>Relacionar com outras disciplinas da formação farmacêutica</li>\r\n</ul>\r\n", "Avançado", 12, 4, "Biotransformação hepática, reações de fase I e fase II, sistema CYP450, indução e inibição enzimática.", "Farmacocinética: Metabolismo", 1 },
                    { 5, "\r\n<h2>Farmacocinética: Excreção</h2>\r\n<p class='lead'>Vias de excreção renal, biliar e pulmonar. Depuração, meia-vida e estado de equilíbrio.</p>\r\n\r\n<h3>Introdução</h3>\r\n<p>Este documento aborda os conceitos fundamentais relacionados a <strong>farmacocinética: excreção</strong>, um tema essencial para a formação do profissional farmacêutico. O domínio deste conteúdo é frequentemente cobrado em provas de concursos e residências farmacêuticas.</p>\r\n\r\n<h3>Conceitos Fundamentais</h3>\r\n<p>A compreensão aprofundada deste tema requer o conhecimento de princípios teóricos e sua aplicação na prática farmacêutica. Os principais pontos a serem estudados incluem definições, classificações, mecanismos e aplicações clínicas.</p>\r\n<ul>\r\n<li>Definições e terminologia técnica específica da área</li>\r\n<li>Classificação e categorização sistemática</li>\r\n<li>Mecanismos de ação e princípios fundamentais</li>\r\n<li>Aplicações práticas no contexto farmacêutico</li>\r\n<li>Correlações clínicas e relevância terapêutica</li>\r\n</ul>\r\n\r\n<h3>Aspectos Práticos</h3>\r\n<p>Na prática profissional, o farmacêutico deve ser capaz de aplicar estes conhecimentos para tomada de decisões clínicas, orientação de pacientes e garantia da qualidade dos serviços prestados.</p>\r\n\r\n<h3>Pontos-Chave para Revisão</h3>\r\n<ul>\r\n<li>Dominar os conceitos teóricos fundamentais</li>\r\n<li>Compreender as aplicações clínicas e práticas</li>\r\n<li>Conhecer a legislação e normas relacionadas</li>\r\n<li>Relacionar com outras disciplinas da formação farmacêutica</li>\r\n</ul>\r\n", "Intermediário", 10, 5, "Vias de excreção renal, biliar e pulmonar. Depuração, meia-vida e estado de equilíbrio.", "Farmacocinética: Excreção", 1 },
                    { 6, "\r\n<h2>Farmacodinâmica: Receptores</h2>\r\n<p class='lead'>Tipos de receptores farmacológicos, mecanismos de transdução de sinal, agonistas e antagonistas.</p>\r\n\r\n<h3>Introdução</h3>\r\n<p>Este documento aborda os conceitos fundamentais relacionados a <strong>farmacodinâmica: receptores</strong>, um tema essencial para a formação do profissional farmacêutico. O domínio deste conteúdo é frequentemente cobrado em provas de concursos e residências farmacêuticas.</p>\r\n\r\n<h3>Conceitos Fundamentais</h3>\r\n<p>A compreensão aprofundada deste tema requer o conhecimento de princípios teóricos e sua aplicação na prática farmacêutica. Os principais pontos a serem estudados incluem definições, classificações, mecanismos e aplicações clínicas.</p>\r\n<ul>\r\n<li>Definições e terminologia técnica específica da área</li>\r\n<li>Classificação e categorização sistemática</li>\r\n<li>Mecanismos de ação e princípios fundamentais</li>\r\n<li>Aplicações práticas no contexto farmacêutico</li>\r\n<li>Correlações clínicas e relevância terapêutica</li>\r\n</ul>\r\n\r\n<h3>Aspectos Práticos</h3>\r\n<p>Na prática profissional, o farmacêutico deve ser capaz de aplicar estes conhecimentos para tomada de decisões clínicas, orientação de pacientes e garantia da qualidade dos serviços prestados.</p>\r\n\r\n<h3>Pontos-Chave para Revisão</h3>\r\n<ul>\r\n<li>Dominar os conceitos teóricos fundamentais</li>\r\n<li>Compreender as aplicações clínicas e práticas</li>\r\n<li>Conhecer a legislação e normas relacionadas</li>\r\n<li>Relacionar com outras disciplinas da formação farmacêutica</li>\r\n</ul>\r\n", "Intermediário", 12, 6, "Tipos de receptores farmacológicos, mecanismos de transdução de sinal, agonistas e antagonistas.", "Farmacodinâmica: Receptores", 1 },
                    { 7, "\r\n<h2>Curva Dose-Resposta</h2>\r\n<p class='lead'>Relação dose-resposta, potência, eficácia máxima, DE50, DL50 e índice terapêutico.</p>\r\n\r\n<h3>Introdução</h3>\r\n<p>Este documento aborda os conceitos fundamentais relacionados a <strong>curva dose-resposta</strong>, um tema essencial para a formação do profissional farmacêutico. O domínio deste conteúdo é frequentemente cobrado em provas de concursos e residências farmacêuticas.</p>\r\n\r\n<h3>Conceitos Fundamentais</h3>\r\n<p>A compreensão aprofundada deste tema requer o conhecimento de princípios teóricos e sua aplicação na prática farmacêutica. Os principais pontos a serem estudados incluem definições, classificações, mecanismos e aplicações clínicas.</p>\r\n<ul>\r\n<li>Definições e terminologia técnica específica da área</li>\r\n<li>Classificação e categorização sistemática</li>\r\n<li>Mecanismos de ação e princípios fundamentais</li>\r\n<li>Aplicações práticas no contexto farmacêutico</li>\r\n<li>Correlações clínicas e relevância terapêutica</li>\r\n</ul>\r\n\r\n<h3>Aspectos Práticos</h3>\r\n<p>Na prática profissional, o farmacêutico deve ser capaz de aplicar estes conhecimentos para tomada de decisões clínicas, orientação de pacientes e garantia da qualidade dos serviços prestados.</p>\r\n\r\n<h3>Pontos-Chave para Revisão</h3>\r\n<ul>\r\n<li>Dominar os conceitos teóricos fundamentais</li>\r\n<li>Compreender as aplicações clínicas e práticas</li>\r\n<li>Conhecer a legislação e normas relacionadas</li>\r\n<li>Relacionar com outras disciplinas da formação farmacêutica</li>\r\n</ul>\r\n", "Intermediário", 8, 7, "Relação dose-resposta, potência, eficácia máxima, DE50, DL50 e índice terapêutico.", "Curva Dose-Resposta", 1 },
                    { 8, "\r\n<h2>Interações Medicamentosas</h2>\r\n<p class='lead'>Interações farmacocinéticas e farmacodinâmicas, sinergismo, antagonismo e implicações clínicas.</p>\r\n\r\n<h3>Introdução</h3>\r\n<p>Este documento aborda os conceitos fundamentais relacionados a <strong>interações medicamentosas</strong>, um tema essencial para a formação do profissional farmacêutico. O domínio deste conteúdo é frequentemente cobrado em provas de concursos e residências farmacêuticas.</p>\r\n\r\n<h3>Conceitos Fundamentais</h3>\r\n<p>A compreensão aprofundada deste tema requer o conhecimento de princípios teóricos e sua aplicação na prática farmacêutica. Os principais pontos a serem estudados incluem definições, classificações, mecanismos e aplicações clínicas.</p>\r\n<ul>\r\n<li>Definições e terminologia técnica específica da área</li>\r\n<li>Classificação e categorização sistemática</li>\r\n<li>Mecanismos de ação e princípios fundamentais</li>\r\n<li>Aplicações práticas no contexto farmacêutico</li>\r\n<li>Correlações clínicas e relevância terapêutica</li>\r\n</ul>\r\n\r\n<h3>Aspectos Práticos</h3>\r\n<p>Na prática profissional, o farmacêutico deve ser capaz de aplicar estes conhecimentos para tomada de decisões clínicas, orientação de pacientes e garantia da qualidade dos serviços prestados.</p>\r\n\r\n<h3>Pontos-Chave para Revisão</h3>\r\n<ul>\r\n<li>Dominar os conceitos teóricos fundamentais</li>\r\n<li>Compreender as aplicações clínicas e práticas</li>\r\n<li>Conhecer a legislação e normas relacionadas</li>\r\n<li>Relacionar com outras disciplinas da formação farmacêutica</li>\r\n</ul>\r\n", "Avançado", 12, 8, "Interações farmacocinéticas e farmacodinâmicas, sinergismo, antagonismo e implicações clínicas.", "Interações Medicamentosas", 1 },
                    { 9, "\r\n<h2>Farmacologia do SNA</h2>\r\n<p class='lead'>Sistema nervoso autônomo: agonistas e antagonistas colinérgicos e adrenérgicos.</p>\r\n\r\n<h3>Introdução</h3>\r\n<p>Este documento aborda os conceitos fundamentais relacionados a <strong>farmacologia do sna</strong>, um tema essencial para a formação do profissional farmacêutico. O domínio deste conteúdo é frequentemente cobrado em provas de concursos e residências farmacêuticas.</p>\r\n\r\n<h3>Conceitos Fundamentais</h3>\r\n<p>A compreensão aprofundada deste tema requer o conhecimento de princípios teóricos e sua aplicação na prática farmacêutica. Os principais pontos a serem estudados incluem definições, classificações, mecanismos e aplicações clínicas.</p>\r\n<ul>\r\n<li>Definições e terminologia técnica específica da área</li>\r\n<li>Classificação e categorização sistemática</li>\r\n<li>Mecanismos de ação e princípios fundamentais</li>\r\n<li>Aplicações práticas no contexto farmacêutico</li>\r\n<li>Correlações clínicas e relevância terapêutica</li>\r\n</ul>\r\n\r\n<h3>Aspectos Práticos</h3>\r\n<p>Na prática profissional, o farmacêutico deve ser capaz de aplicar estes conhecimentos para tomada de decisões clínicas, orientação de pacientes e garantia da qualidade dos serviços prestados.</p>\r\n\r\n<h3>Pontos-Chave para Revisão</h3>\r\n<ul>\r\n<li>Dominar os conceitos teóricos fundamentais</li>\r\n<li>Compreender as aplicações clínicas e práticas</li>\r\n<li>Conhecer a legislação e normas relacionadas</li>\r\n<li>Relacionar com outras disciplinas da formação farmacêutica</li>\r\n</ul>\r\n", "Intermediário", 12, 9, "Sistema nervoso autônomo: agonistas e antagonistas colinérgicos e adrenérgicos.", "Farmacologia do SNA", 1 },
                    { 10, "\r\n<h2>Anti-inflamatórios Não Esteroidais</h2>\r\n<p class='lead'>AINEs: mecanismo de inibição da COX, classificação, indicações e efeitos adversos.</p>\r\n\r\n<h3>Introdução</h3>\r\n<p>Este documento aborda os conceitos fundamentais relacionados a <strong>anti-inflamatórios não esteroidais</strong>, um tema essencial para a formação do profissional farmacêutico. O domínio deste conteúdo é frequentemente cobrado em provas de concursos e residências farmacêuticas.</p>\r\n\r\n<h3>Conceitos Fundamentais</h3>\r\n<p>A compreensão aprofundada deste tema requer o conhecimento de princípios teóricos e sua aplicação na prática farmacêutica. Os principais pontos a serem estudados incluem definições, classificações, mecanismos e aplicações clínicas.</p>\r\n<ul>\r\n<li>Definições e terminologia técnica específica da área</li>\r\n<li>Classificação e categorização sistemática</li>\r\n<li>Mecanismos de ação e princípios fundamentais</li>\r\n<li>Aplicações práticas no contexto farmacêutico</li>\r\n<li>Correlações clínicas e relevância terapêutica</li>\r\n</ul>\r\n\r\n<h3>Aspectos Práticos</h3>\r\n<p>Na prática profissional, o farmacêutico deve ser capaz de aplicar estes conhecimentos para tomada de decisões clínicas, orientação de pacientes e garantia da qualidade dos serviços prestados.</p>\r\n\r\n<h3>Pontos-Chave para Revisão</h3>\r\n<ul>\r\n<li>Dominar os conceitos teóricos fundamentais</li>\r\n<li>Compreender as aplicações clínicas e práticas</li>\r\n<li>Conhecer a legislação e normas relacionadas</li>\r\n<li>Relacionar com outras disciplinas da formação farmacêutica</li>\r\n</ul>\r\n", "Intermediário", 10, 10, "AINEs: mecanismo de inibição da COX, classificação, indicações e efeitos adversos.", "Anti-inflamatórios Não Esteroidais", 1 },
                    { 11, "\r\n<h2>Corticosteroides</h2>\r\n<p class='lead'>Glicocorticoides e mineralocorticoides: mecanismo, indicações, efeitos colaterais e retirada gradual.</p>\r\n\r\n<h3>Introdução</h3>\r\n<p>Este documento aborda os conceitos fundamentais relacionados a <strong>corticosteroides</strong>, um tema essencial para a formação do profissional farmacêutico. O domínio deste conteúdo é frequentemente cobrado em provas de concursos e residências farmacêuticas.</p>\r\n\r\n<h3>Conceitos Fundamentais</h3>\r\n<p>A compreensão aprofundada deste tema requer o conhecimento de princípios teóricos e sua aplicação na prática farmacêutica. Os principais pontos a serem estudados incluem definições, classificações, mecanismos e aplicações clínicas.</p>\r\n<ul>\r\n<li>Definições e terminologia técnica específica da área</li>\r\n<li>Classificação e categorização sistemática</li>\r\n<li>Mecanismos de ação e princípios fundamentais</li>\r\n<li>Aplicações práticas no contexto farmacêutico</li>\r\n<li>Correlações clínicas e relevância terapêutica</li>\r\n</ul>\r\n\r\n<h3>Aspectos Práticos</h3>\r\n<p>Na prática profissional, o farmacêutico deve ser capaz de aplicar estes conhecimentos para tomada de decisões clínicas, orientação de pacientes e garantia da qualidade dos serviços prestados.</p>\r\n\r\n<h3>Pontos-Chave para Revisão</h3>\r\n<ul>\r\n<li>Dominar os conceitos teóricos fundamentais</li>\r\n<li>Compreender as aplicações clínicas e práticas</li>\r\n<li>Conhecer a legislação e normas relacionadas</li>\r\n<li>Relacionar com outras disciplinas da formação farmacêutica</li>\r\n</ul>\r\n", "Intermediário", 10, 11, "Glicocorticoides e mineralocorticoides: mecanismo, indicações, efeitos colaterais e retirada gradual.", "Corticosteroides", 1 },
