                values: new object[,]
                {
                    { 1, "Fácil", "Qual fase da farmacocinética envolve a passagem do fármaco do local de administração para a circulação sistêmica?", "A absorção é a primeira fase farmacocinética, envolvendo a transferência do fármaco do local de administração para a corrente sanguínea.", 1, 0, 1 },
                    { 2, "Médio", "O volume de distribuição (Vd) elevado indica que o fármaco:", "Um Vd elevado indica ampla distribuição tecidual, ultrapassando o volume plasmático.", 2, 0, 1 },
                    { 3, "Médio", "As reações de fase I do metabolismo hepático envolvem principalmente:", "As reações de fase I (funcionalização) incluem oxidação, redução e hidrólise, catalisadas pelo CYP450.", 3, 0, 1 },
                    { 4, "Fácil", "A biodisponibilidade de um fármaco administrado por via intravenosa é:", "Por via IV, o fármaco atinge diretamente a circulação sistêmica sem passagem pelo efeito de primeira passagem, resultando em biodisponibilidade de 100%.", 4, 0, 1 },
                    { 5, "Médio", "Qual enzima do CYP450 é responsável pelo metabolismo da maioria dos fármacos?", "O CYP3A4 metaboliza aproximadamente 50% dos fármacos de uso clínico, sendo a isoforma mais importante.", 5, 0, 1 },
                    { 6, "Médio", "O índice terapêutico de um fármaco é calculado pela razão:", "O índice terapêutico é a razão entre a dose letal mediana (DL50) e a dose efetiva mediana (DE50). Quanto maior, mais seguro o fármaco.", 6, 0, 1 },
                    { 7, "Médio", "Um antagonista competitivo reversível:", "O antagonista competitivo reversível compete pelo mesmo sítio, deslocando a curva para a direita, mas o efeito máximo pode ser atingido com doses maiores de agonista.", 7, 0, 1 },
                    { 8, "Fácil", "A meia-vida de eliminação (t½) é o tempo necessário para:", "A meia-vida é o tempo para a concentração plasmática cair 50%. São necessárias ~5 meias-vidas para alcançar o estado de equilíbrio.", 8, 0, 1 },
                    { 9, "Fácil", "AINEs como ibuprofeno atuam inibindo:", "Os AINEs tradicionais inibem de forma não seletiva a COX-1 e COX-2, reduzindo a síntese de prostaglandinas.", 9, 0, 1 },
                    { 10, "Médio", "O principal efeito adverso dos aminoglicosídeos é:", "Os aminoglicosídeos podem causar dano renal (nefrotoxicidade) e lesão do VIII par craniano (ototoxicidade).", 10, 0, 1 },
                    { 11, "Fácil", "Qual classe de anti-hipertensivo inibe a enzima conversora de angiotensina?", "Os IECA (Inibidores da Enzima Conversora de Angiotensina) como enalapril e captopril bloqueiam a conversão de angiotensina I em II.", 11, 0, 1 },
                    { 12, "Médio", "A síndrome serotoninérgica pode ocorrer com a associação de:", "A síndrome serotoninérgica é uma emergência causada por excesso de serotonina, geralmente pela combinação de dois serotoninérgicos (ex: ISRS + IMAO).", 12, 0, 1 },
                    { 13, "Médio", "A metformina atua principalmente:", "A metformina é uma biguanida que atua primariamente no fígado, reduzindo a gliconeogênese e aumentando a sensibilidade à insulina.", 13, 0, 1 },
                    { 14, "Fácil", "O antídoto para intoxicação por varfarina é:", "A vitamina K é o antídoto específico para varfarina, pois restaura a síntese dos fatores de coagulação dependentes de vitamina K (II, VII, IX, X).", 14, 0, 1 },
                    { 15, "Médio", "Os receptores muscarínicos M3 estão localizados principalmente em:", "Os receptores M3 medeiam contração do músculo liso (brônquios, bexiga, TGI) e secreção glandular.", 15, 0, 1 },
                    { 16, "Fácil", "Qual é o mecanismo de ação das cefalosporinas?", "As cefalosporinas, como os demais beta-lactâmicos, inibem a transpeptidase (PBP), bloqueando a síntese do peptidoglicano da parede celular.", 16, 0, 1 },
                    { 17, "Fácil", "A fluoxetina pertence à classe dos:", "A fluoxetina é um ISRS que bloqueia seletivamente o transportador de serotonina (SERT), aumentando a disponibilidade de 5-HT na fenda sináptica.", 17, 0, 1 },
                    { 18, "Fácil", "O efeito de primeira passagem hepática:", "O metabolismo de primeira passagem ocorre quando o fármaco oral passa pelo fígado antes de atingir a circulação sistêmica, reduzindo sua biodisponibilidade.", 18, 0, 1 },
                    { 19, "Médio", "Os inibidores de SGLT2 (gliflozinas) atuam:", "As gliflozinas (dapagliflozina, empagliflozina) inibem o cotransportador SGLT2 no túbulo proximal renal, promovendo glicosúria.", 19, 0, 1 },
                    { 20, "Médio", "A clozapina é um antipsicótico atípico indicado para:", "A clozapina é reservada para esquizofrenia resistente a outros antipsicóticos, mas requer monitoramento de agranulocitose.", 20, 0, 1 },
                    { 21, "Médio", "O pKa de um fármaco ácido fraco determina que ele será melhor absorvido em:", "Ácidos fracos ficam mais na forma não ionizada em pH ácido, favorecendo absorção no estômago (teoria da partição de pH).", 21, 0, 1 },
                    { 22, "Fácil", "A nitroglicerina sublingual é usada para:", "A nitroglicerina sublingual libera óxido nítrico, causa vasodilatação venosa e alívio rápido da angina pectoris.", 22, 0, 1 },
                    { 23, "Médio", "Qual é o principal efeito adverso dos corticosteroides em uso prolongado?", "O uso crônico causa face em lua cheia, estrias, hiperglicemia, osteoporose, imunossupressão — síndrome de Cushing iatrogênica.", 23, 0, 1 },
                    { 24, "Fácil", "A naloxona é antagonista específico de receptores:", "A naloxona é antagonista competitivo de receptores opioides mu, kappa e delta, usada na reversão de overdose de opioides.", 24, 0, 1 },
                    { 25, "Fácil", "A atropina bloqueia receptores:", "A atropina é um antagonista muscarínico não seletivo, bloqueando M1-M5, causando taquicardia, midríase, boca seca.", 25, 0, 1 },
                    { 26, "Fácil", "O sinergismo farmacológico ocorre quando:", "No sinergismo, a combinação de dois fármacos produz efeito superior ao esperado pela simples adição dos efeitos individuais.", 26, 0, 1 },
                    { 27, "Médio", "A digoxina atua no coração por:", "A digoxina inibe a Na+/K+-ATPase, aumentando o cálcio intracelular e a força de contração (efeito inotrópico positivo).", 27, 0, 1 },
                    { 28, "Fácil", "O omeprazol pertence à classe dos:", "O omeprazol inibe irreversivelmente a H+/K+-ATPase (bomba de prótons) das células parietais gástricas.", 28, 0, 1 },
                    { 29, "Médio", "A resistência bacteriana mediada por beta-lactamases é superada por:", "Inibidores de beta-lactamase (clavulanato, sulbactam, tazobactam) protegem o beta-lactâmico da degradação enzimática.", 29, 0, 1 },
                    { 30, "Difícil", "A fenitoína apresenta cinética de eliminação:", "A fenitoína é um exemplo clássico de fármaco com cinética de saturação (Michaelis-Menten), onde pequenos aumentos de dose causam grandes elevações de nível sérico.", 30, 0, 1 },
                    { 31, "Médio", "O carbonato de lítio é utilizado como:", "O lítio é o estabilizador de humor padrão-ouro para transtorno bipolar, requerendo monitoramento de nível sérico (0,6-1,2 mEq/L).", 31, 0, 1 },
                    { 32, "Médio", "A taquifilaxia é definida como:", "A taquifilaxia (dessensibilização rápida) é a perda progressiva e rápida do efeito farmacológico com administrações repetidas em curto intervalo.", 32, 0, 1 },
                    { 33, "Fácil", "Qual fármaco é considerado protótipo dos betabloqueadores não seletivos?", "O propranolol bloqueia beta-1 e beta-2, sendo o protótipo dos betabloqueadores não seletivos. Atenolol e metoprolol são beta-1 seletivos.", 33, 0, 1 },
                    { 34, "Fácil", "A via de administração que evita completamente o efeito de primeira passagem é:", "A via IV introduz o fármaco diretamente na circulação, eliminando qualquer metabolismo pré-sistêmico.", 34, 0, 1 },
                    { 35, "Fácil", "Os agonistas beta-2 adrenérgicos como salbutamol são indicados para:", "O salbutamol é um agonista seletivo beta-2 que relaxa a musculatura lisa brônquica, sendo broncodilatador de curta ação.", 35, 0, 1 },
                    { 36, "Médio", "A janela terapêutica de um fármaco é:", "A janela terapêutica é o intervalo entre a concentração efetiva mínima (CEM) e a concentração tóxica mínima (CTM).", 36, 0, 1 },
                    { 37, "Médio", "O metotrexato atua como antagonista de:", "O metotrexato é um antimetabólito que inibe a DHFR, bloqueando a síntese de purinas e pirimidinas.", 37, 0, 1 },
                    { 38, "Médio", "Os diuréticos de alça (furosemida) atuam no:", "A furosemida inibe o cotransportador Na+/K+/2Cl- no ramo ascendente espesso da alça de Henle, sendo o diurético mais potente.", 38, 0, 1 },
                    { 39, "Médio", "A anfotericina B atua contra fungos por:", "A anfotericina B é um poliênico que se liga ao ergosterol, formando poros na membrana fúngica e causando lise celular.", 39, 0, 1 },
                    { 40, "Médio", "A varfarina exerce seu efeito anticoagulante por:", "A varfarina inibe a VKORC1 (vitamina K epóxi-redutase), impedindo a carboxilação dos fatores II, VII, IX e X.", 40, 0, 1 },
                    { 41, "Fácil", "A fase III do ensaio clínico tem como principal objetivo:", "A fase III envolve milhares de pacientes para confirmar eficácia terapêutica e detectar efeitos adversos comuns.", 1, 0, 2 },
                    { 42, "Médio", "A monitorização terapêutica é obrigatória para:", "Fármacos com janela terapêutica estreita como vancomicina, lítio e digoxina requerem dosagem sérica rotineira.", 2, 0, 2 },
                    { 43, "Médio", "Os critérios de Beers são utilizados para:", "Os critérios de Beers (AGS) listam fármacos que devem ser evitados em idosos ≥65 anos pelo risco de efeitos adversos.", 3, 0, 2 },
                    { 44, "Fácil", "Reação adversa tipo A (augmented) é caracterizada por:", "RAM tipo A são extensão do efeito farmacológico, dose-dependentes, previsíveis e tratáveis com redução de dose.", 4, 0, 2 },
                    { 45, "Médio", "Na insuficiência renal, o ajuste de dose é baseado em:", "A TFG (estimada por CKD-EPI ou Cockcroft-Gault) determina a necessidade e magnitude do ajuste posológico.", 5, 0, 2 },
                    { 46, "Fácil", "Qual fase do ensaio clínico avalia farmacocinética em voluntários sadios?", "A fase I é realizada em poucos voluntários sadios para avaliar segurança, tolerabilidade e farmacocinética.", 6, 1, 2 },
                    { 47, "Médio", "A farmacovigilância ativa ocorre na fase:", "A fase IV (pós-comercialização) monitora efeitos adversos raros e interações em grandes populações.", 7, 3, 2 },
                    { 48, "Médio", "A classificação de risco na gestação categoria X da FDA significa:", "Categoria X: evidência de risco fetal em humanos/animais, contraindicado na gestação.", 8, 0, 2 },
                    { 49, "Fácil", "O ensaio clínico do tipo duplo-cego significa que:", "No duplo-cego, investigador e paciente são cegados para reduzir viés.", 9, 0, 2 },
                    { 50, "Médio", "A fórmula de Cockcroft-Gault estima:", "A fórmula de Cockcroft-Gault calcula o ClCr considerando idade, peso, creatinina sérica e sexo.", 10, 1, 2 },
                    { 51, "Fácil", "Qual é o nível de evidência mais alto na MBE?", "A revisão sistemática com meta-análise de ECRs é o topo da pirâmide de evidência.", 11, 1, 2 },
                    { 52, "Médio", "O NNT (Número Necessário para Tratar) indica:", "NNT = 1/RAR (Redução Absoluta de Risco). Quanto menor, mais eficaz o tratamento.", 12, 1, 2 },
                    { 53, "Fácil", "A escada analgésica da OMS tem quantos degraus?", "A escada da OMS tem 3 degraus: 1) não opioides, 2) opioides fracos, 3) opioides fortes.", 13, 2, 2 },
                    { 54, "Fácil", "Na farmacoterapia pediátrica, o cálculo de dose pode ser feito por:", "Dose pediátrica é calculada por peso (mg/kg) ou superfície corporal (mg/m²) para individualização.", 14, 2, 2 },
                    { 55, "Médio", "A Child-Pugh classifica a gravidade de:", "O escore de Child-Pugh (A/B/C) estratifica a doença hepática com base em bilirrubina, albumina, INR, ascite e encefalopatia.", 15, 3, 2 },
                    { 56, "Difícil", "Endpoints substitutos (surrogate endpoints) em ensaios clínicos:", "Endpoints substitutos (ex: HbA1c, LDL) são marcadores que representam desfechos clínicos relevantes.", 16, 2, 2 },
                    { 57, "Fácil", "O placebo é utilizado em ensaios clínicos para:", "O grupo placebo permite separar o efeito farmacológico real do efeito psicológico/expectativa.", 17, 3, 2 },
                    { 58, "Médio", "A polifarmácia no idoso é definida como uso concomitante de:", "Polifarmácia é classicamente definida como uso simultâneo de 5 ou mais medicamentos.", 18, 2, 2 },
                    { 59, "Médio", "A descontinuação abrupta de betabloqueador pode causar:", "A retirada abrupta de betabloqueadores causa up-regulation de receptores beta, levando a rebote simpático.", 19, 1, 2 },
                    { 60, "Fácil", "Qual escala é usada para avaliar causalidade de RAM?", "A Escala de Naranjo (algoritmo de causalidade) classifica a probabilidade de uma RAM em definitiva, provável, possível ou duvidosa.", 20, 2, 2 },
                    { 61, "Fácil", "A prescrição off-label refere-se ao uso de medicamento:", "Uso off-label é a prescrição para indicação, dose, via ou população diferente da aprovada na bula/registro.", 21, 0, 2 },
                    { 62, "Médio", "O estudo de bioequivalência compara:", "Bioequivalência demonstra que genérico e referência possuem mesma biodisponibilidade (Cmax e AUC equivalentes).", 22, 2, 2 },
                    { 63, "Fácil", "A principal causa de não adesão ao tratamento é:", "Regime posológico complexo e esquecimento são as principais causas de não adesão ao tratamento farmacológico.", 23, 1, 2 },
                    { 64, "Difícil", "O conceito de NNH (Número Necessário para Causar Dano) refere-se a:", "NNH indica quantos pacientes precisam ser tratados para causar um evento adverso adicional vs. controle.", 24, 0, 2 },
                    { 65, "Médio", "Na farmacoterapia da asma, o step 1 do GINA recomenda:", "O step 1 do GINA 2023 recomenda CI-formoterol em dose baixa conforme necessidade (sem tratamento de manutenção).", 25, 3, 2 },
                    { 66, "Médio", "A interação entre varfarina e amiodarona resulta em:", "A amiodarona inibe o CYP2C9, aumentando os níveis de varfarina e o risco de sangramento.", 26, 1, 2 },
                    { 67, "Fácil", "O conceito de farmacoterapia racional inclui:", "Farmacoterapia racional: fármaco adequado, dose correta, duração adequada, menor custo, com eficácia e segurança.", 27, 1, 2 },
                    { 68, "Médio", "Reações adversas do tipo B (bizarre) são:", "RAM tipo B são idiossincráticas, raras, imprevisíveis, não dose-dependentes, geralmente imunomediadas ou farmacogenéticas.", 28, 2, 2 },
                    { 69, "Fácil", "O termo farmacologia clínica enfatiza:", "A farmacologia clínica integra conhecimentos farmacológicos à prática terapêutica no contexto do paciente.", 29, 1, 2 },
                    { 70, "Médio", "O clearance renal de fármacos depende de:", "O clearance renal é resultado de filtração glomerular + secreção tubular ativa – reabsorção tubular.", 30, 0, 2 },
                    { 71, "Difícil", "A RAM tipo D (delayed) é aquela que:", "RAM tipo D são efeitos tardios que surgem após uso prolongado ou exposição prévia (ex.: carcinogênese, teratogênese).", 31, 1, 2 },
                    { 72, "Fácil", "Na farmacoterapia do diabetes tipo 2, a metformina é primeira linha porque:", "A metformina é primeira linha no DM2 por eficácia, segurança (baixo risco de hipoglicemia), benefício CV e baixo custo.", 32, 1, 2 },
                    { 73, "Fácil", "O antibiótico empírico deve ser selecionado com base em:", "A antibioticoterapia empírica considera o sítio de infecção, os patógenos prováveis e o perfil de resistência local.", 33, 1, 2 },
                    { 74, "Médio", "A taxa de adesão ao tratamento crônico gira em torno de:", "Segundo a OMS, a adesão ao tratamento crônico é de aproximadamente 50% em países desenvolvidos.", 34, 2, 2 },
                    { 75, "Fácil", "O estudo randomizado controlado (ECR) é considerado padrão-ouro porque:", "A randomização distribui igualmente fatores de confusão entre os grupos, minimizando viés.", 35, 1, 2 },
                    { 76, "Difícil", "ITT (Intenção de Tratar) na análise de ensaios clínicos significa:", "A análise por intenção de tratar inclui todos os pacientes via grupo de alocação original, preservando a randomização.", 36, 1, 2 },
                    { 77, "Difícil", "O ajuste de dose na insuficiência hepática é complexo porque:", "Diferente do rim (TFG), não há marcador preciso para capacidade metabólica hepática, dificultando ajustes.", 37, 1, 2 },
                    { 78, "Médio", "O desmame (tapering) de corticosteroides crônicos é necessário para:", "O uso crônico suprime o eixo HPA; a retirada abrupta pode causar insuficiência adrenal potencialmente fatal.", 38, 1, 2 },
                    { 79, "Difícil", "Qual parâmetro farmacocinético é mais importante para eficácia de aminoglicosídeos?", "Aminoglicosídeos são concentração-dependentes; a relação Cmax/CIM determina a eficácia bactericida.", 39, 1, 2 },
                    { 80, "Médio", "A prescrição farmacêutica no Brasil é regulamentada pela resolução:", "A Resolução CFF nº 586/2013 regulamenta a prescrição farmacêutica no Brasil.", 40, 1, 2 },
                    { 81, "Fácil", "Os alcaloides são compostos do metabolismo secundário que contêm:", "Alcaloides são bases orgânicas nitrogenadas, geralmente com nitrogênio em anel heterocíclico, de origem natural.", 1, 0, 3 },
                    { 82, "Médio", "A rota do ácido mevalônico origina:", "A rota mevalônica produz isopentenil pirofosfato (IPP), precursor de todos os terpenoides e esteroides.", 2, 0, 3 },
                    { 83, "Médio", "A percolação é um método de extração que utiliza:", "Na percolação, o solvente passa continuamente pela droga vegetal em um percolador, extraindo progressivamente os ativos.", 3, 0, 3 },
                    { 84, "Médio", "Os glicosídeos cardiotônicos da Digitalis purpurea atuam por:", "Digoxina e digitoxina inibem a bomba de sódio-potássio, aumentando o cálcio intracelular e a contração cardíaca.", 4, 0, 3 },
                    { 85, "Fácil", "A RENISUS é uma lista de:", "A RENISUS lista 71 plantas medicinais com potencial para gerar produtos de interesse ao SUS.", 5, 0, 3 },
                    { 86, "Médio", "Os flavonoides pertencem à classe de metabólitos derivados da rota:", "Os flavonoides são polifenóis biossintetizados pela rota mista do ácido chiquímico e acetato-malonato.", 6, 1, 3 },
                    { 87, "Fácil", "O óleo essencial de eucalipto é obtido principalmente por:", "Óleos essenciais voláteis são extraídos por destilação por arraste de vapor, método clássico da farmacognosia.", 7, 2, 3 },
                    { 88, "Fácil", "A Senna alexandrina (sene) contém derivados de:", "O sene contém senosídeos (antraquinonas), que atuam como laxantes estimulantes do cólon.", 8, 2, 3 },
                    { 89, "Médio", "Os taninos hidrolisáveis diferem dos condensados por:", "Taninos hidrolisáveis são ésteres de ácido gálico/elágico com açúcares, hidrolisáveis por enzimas ou ácidos.", 9, 1, 3 },
                    { 90, "Fácil", "O Ginkgo biloba é indicado principalmente para:", "O extrato padronizado de Ginkgo biloba (EGb 761) melhora a circulação cerebral e periférica.", 10, 2, 3 },
                    { 91, "Médio", "A padronização de fitoterápicos refere-se a:", "A padronização garante que o fitoterápico tenha teor definido de marcador/princípio ativo.", 11, 1, 3 },
                    { 92, "Médio", "A extração por Soxhlet é um método:", "O Soxhlet permite extração contínua com solvente quente, ideal para compostos termoestáveis.", 12, 1, 3 },
                    { 93, "Fácil", "Qual técnica cromatográfica é utilizada para identificação rápida de drogas vegetais?", "A CCD é técnica simples, rápida e barata para identificação e comparação de perfis cromatográficos de drogas vegetais.", 13, 0, 3 },
                    { 94, "Fácil", "A Valeriana officinalis tem propriedades:", "A valeriana contém valepotriatos e ácido valerênico que atuam no sistema GABAérgico, com efeito sedativo.", 14, 2, 3 },
                    { 95, "Médio", "As saponinas possuem propriedade tensoativa porque:", "Saponinas são anfifílicas (aglicona lipofílica + açúcares hidrofílicos), reduzindo a tensão superficial.", 15, 2, 3 },
                    { 96, "Fácil", "O canabidiol (CBD) se diferencia do THC por:", "O CBD é não psicoativo (diferente do THC) e apresenta propriedades anticonvulsivantes e ansiolíticas.", 16, 1, 3 },
                    { 97, "Médio", "O controle de qualidade de drogas vegetais na Farmacopeia Brasileira inclui:", "A FB exige identificação botânica, ensaios de pureza (cinzas, matéria estranha), teor de marcadores e microbiologia.", 17, 1, 3 },
                    { 98, "Fácil", "A decocção é um método de extração que:", "Na decocção, a droga é fervida em água, método indicado para partes duras (cascas, raízes).", 18, 1, 3 },
                    { 99, "Difícil", "Cumarinas são compostos derivados de:", "Cumarinas são lactonas do ácido orto-hidroxicinâmico, derivadas da rota do ácido chiquímico.", 19, 1, 3 },
                    { 100, "Fácil", "A etnofarmacologia estuda:", "A etnofarmacologia investiga o conhecimento tradicional sobre plantas medicinais e busca validação científica.", 20, 1, 3 },
                    { 101, "Fácil", "O barbatimão (Stryphnodendron adstringens) é rico em:", "O barbatimão é fonte rica de taninos condensados com ação cicatrizante e antimicrobiana.", 21, 2, 3 },
                    { 102, "Médio", "Os monoterpenos possuem quantos carbonos?", "Monoterpenos possuem 10 carbonos (2 unidades isoprênicas de 5C). São componentes frequentes de óleos essenciais.", 22, 2, 3 },
                    { 103, "Médio", "A RDC 26/2014 da ANVISA regulamenta:", "A RDC 26/2014 define categorias (fitoterápico e produto tradicional fitoterápico) e requisitos para registro.", 23, 2, 3 },
                    { 104, "Fácil", "A própolis apresenta como principal ação farmacológica:", "A própolis é rica em flavonoides e ácidos fenólicos, com atividade antimicrobiana, anti-inflamatória e antioxidante.", 24, 1, 3 },
                    { 105, "Médio", "O pilocarpus (jaborandi) é fonte natural de:", "O Pilocarpus microphyllus é fonte de pilocarpina, alcaloide colinérgico usado no tratamento de glaucoma e xerostomia.", 25, 1, 3 },
                    { 106, "Fácil", "A maceração se diferencia da percolação por:", "Na maceração, a droga fica imersa no solvente sem renovação contínua, por tempo prolongado.", 26, 1, 3 },
                    { 107, "Médio", "Os triterpenos são terpenoides com quantos carbonos?", "Triterpenos possuem 30 carbonos (6 unidades isoprênicas). O esqualeno e o lupeol são exemplos.", 27, 2, 3 },
                    { 108, "Fácil", "O metabolismo primário diferencia-se do secundário por:", "O metabolismo primário (glicólise, Krebs, fotossíntese) é essencial à vida, enquanto o secundário produz substâncias adaptativas.", 28, 1, 3 },
                    { 109, "Médio", "A Chamomilla recutita (camomila) é rica em:", "O óleo essencial da camomila contém α-bisabolol e camazuleno (anti-inflamatórios), além de flavonoides como apigenina.", 29, 1, 3 },
                    { 110, "Médio", "A CLAE é utilizada em farmacognosia para:", "A CLAE permite separação, identificação e quantificação de marcadores em extratos vegetais com alta resolução.", 30, 1, 3 },
                    { 111, "Fácil", "A bioprospecção é o processo de:", "A bioprospecção explora sistematicamente a biodiversidade em busca de moléculas com potencial farmacêutico.", 31, 1, 3 },
                    { 112, "Difícil", "As lignanas são compostos formados pela:", "Lignanas são dímeros de fenilpropanoides (C6-C3), com atividades antitumorais e anti-inflamatórias.", 32, 1, 3 },
                    { 113, "Fácil", "A Mikania glomerata (guaco) é utilizada tradicionalmente como:", "O guaco contém cumarina e é utilizado como broncodilatador e expectorante no tratamento de afecções respiratórias.", 33, 1, 3 },
                    { 114, "Fácil", "O alcaloide morfina é extraído de:", "A morfina é extraída do ópio (Papaver somniferum), sendo o protótipo dos analgésicos opioides.", 34, 1, 3 },
                    { 115, "Médio", "A quinina, usada contra a malária, é extraída de:", "A quinina é um alcaloide da casca de Cinchona, usado historicamente contra malária.", 35, 2, 3 },
                    { 116, "Difícil", "A extração por fluido supercrítico (CO2) tem como vantagem:", "A extração com CO2 supercrítico não deixa resíduos de solvente, é seletiva e preserva compostos termolábeis.", 36, 1, 3 },
                    { 117, "Médio", "As catequinas são exemplos de:", "Catequinas e procianidinas são taninos condensados com potente atividade antioxidante.", 37, 2, 3 },
                    { 118, "Médio", "O ácido chiquímico é precursor biossintético de:", "A rota do ácido chiquímico origina fenilalanina e tirosina, precursores de fenilpropanoides, cumarinas e flavonoides.", 38, 2, 3 },
                    { 119, "Médio", "A atividade de água (Aw) é importante para drogas vegetais porque:", "Aw elevada favorece crescimento de fungos e bactérias, exigindo secagem adequada da droga vegetal.", 39, 2, 3 },
                    { 120, "Fácil", "A RDC 67/2007 da ANVISA regulamenta:", "A RDC 67/2007 estabelece requisitos de BPM para farmácias magistrais (estrutura, processos, pessoal, documentação).", 1, 0, 4 },
                    { 121, "Fácil", "Qual forma farmacêutica é uma dispersão grosseira de sólido insolúvel em líquido?", "Suspensões são sistemas heterogêneos com partículas sólidas insolúveis dispersas em veículo líquido.", 2, 2, 4 },
                    { 122, "Médio", "O HLB (Equilíbrio Hidrófilo-Lipófilo) é importante para:", "O HLB guia a seleção de tensoativos: HLB baixo = emulsão A/O, HLB alto = emulsão O/A.", 3, 1, 4 },
                    { 123, "Fácil", "Cápsulas duras de gelatina são preenchidas com:", "Cápsulas duras são invólucros de gelatina preenchidos com pós, grânulos, pellets ou microcomprimidos.", 4, 1, 4 },
                    { 124, "Fácil", "O conservante mais utilizado em formulações líquidas orais é:", "Metilparabeno (e propilparabeno) são conservantes antimicrobianos amplamente usados em formulações líquidas.", 5, 1, 4 },
                    { 125, "Fácil", "Uma emulsão O/A possui:", "Emulsão O/A: fase oleosa dispersa (interna) em fase aquosa contínua (externa). Lavável com água.", 6, 1, 4 },
                    { 126, "Fácil", "A isotonia de colírios é importante para:", "Soluções hipotônicas ou hipertônicas causam desconforto ocular; a isotonia (≈0,9% NaCl eq.) previne irritação.", 7, 1, 4 },
                    { 127, "Fácil", "O supositório é uma forma farmacêutica:", "Supositórios são formas sólidas para administração retal, que fundem ou dissolvem na temperatura corporal.", 8, 2, 4 },
                    { 128, "Médio", "A pomada se diferencia do creme por:", "Pomadas têm base monofásica (lipofílica geralmente); cremes são emulsões (O/A ou A/O) semissólidas.", 9, 1, 4 },
                    { 129, "Médio", "O xarope simples contém sacarose na concentração de aproximadamente:", "O xarope simples contém cerca de 85% p/v de sacarose, conferindo viscosidade e autoconservação.", 10, 3, 4 },
                    { 130, "Médio", "A base mais utilizada para supositórios é:", "Manteiga de cacau é a base clássica, fundindo entre 34-36°C. PEGs são bases hidrossolúveis alternativas.", 11, 1, 4 },
                    { 131, "Fácil", "A incompatibilidade farmacotécnica ocorre quando:", "Incompatibilidade: reação físico-química entre componentes que compromete estabilidade, eficácia ou segurança.", 12, 1, 4 },
                    { 132, "Fácil", "Elixires são preparações:", "Elixires são soluções límpidas, hidroalcoólicas, edulcoradas e aromatizadas para uso oral.", 13, 2, 4 },
                    { 133, "Médio", "O agente suspensor CMC-Na (carboximetilcelulose sódica) atua:", "A CMC-Na é polímero viscosificante que aumenta a viscosidade do meio, retardando a sedimentação de partículas.", 14, 1, 4 },
                    { 134, "Fácil", "A esterilização por autoclave utiliza:", "Autoclavagem: 121°C, 1 atm acima da pressão atmosférica, 15 minutos. Método mais confiável de esterilização.", 15, 1, 4 },
                    { 135, "Médio", "O fator de deslocamento em supositórios serve para:", "O fator de deslocamento permite calcular a quantidade de base a subtrair para acomodar o fármaco no molde.", 16, 1, 4 },
                    { 136, "Fácil", "Formas farmacêuticas de liberação modificada incluem:", "Liberação modificada: prolongada (slow release), retardada (entérica), pulsátil e programada.", 17, 1, 4 },
                    { 137, "Difícil", "A água purificada para formulações magistrais deve ter condutividade máxima de:", "Água purificada: condutividade ≤1,3 µS/cm e TOC ≤500 ppb, produzida por deionização ou osmose reversa.", 18, 0, 4 },
                    { 138, "Médio", "O BHT (butilidroxitolueno) é utilizado em formulações como:", "O BHT é antioxidante sintético que previne a oxidação de lipídios em formulações farmacêuticas.", 19, 1, 4 },
                    { 139, "Médio", "A granulometria de pós é importante na manipulação porque:", "O tamanho de partícula influencia taxa de dissolução, escoamento, uniformidade de conteúdo e biodisponibilidade.", 20, 1, 4 },
                    { 140, "Fácil", "A goma xantana em formulações semissólidas atua como:", "A goma xantana é polissacarídeo utilizado como espessante/gelificante em géis e cremes farmacêuticos.", 21, 1, 4 },
                    { 141, "Médio", "O pH ideal de colírios deve estar na faixa de:", "O pH ideal ocular é 7,4, sendo tolerável a faixa de 6,5 a 8,5 para minimizar irritação.", 22, 2, 4 },
                    { 142, "Fácil", "A lactose é frequentemente usada em cápsulas como:", "A lactose é o diluente mais usado em cápsulas magistrais, servindo como veículo de enchimento.", 23, 2, 4 },
                    { 143, "Médio", "O sistema de classificação biofarmacêutica (SCB) classe II indica fármaco com:", "SCB classe II: baixa solubilidade, alta permeabilidade. A dissolução é o passo limitante da absorção.", 24, 1, 4 },
                    { 144, "Médio", "O EDTA dissódico em formulações atua como:", "O EDTA sequestra íons metálicos que catalisam oxidação e inativam conservantes, potencializando seu efeito.", 25, 1, 4 },
                    { 145, "Médio", "A dispersão coloidal se diferencia de solução verdadeira por:", "Dispersões coloidais possuem partículas na faixa de 1 nm a 1 µm, entre soluções e suspensões.", 26, 0, 4 },
                    { 146, "Fácil", "O lubrificante mais utilizado na manipulação de cápsulas é:", "O estearato de magnésio é lubrificante que melhora o fluxo do pó e previne aderência nas máquinas.", 27, 2, 4 },
                    { 147, "Fácil", "A vantagem da cápsula vegetal (HPMC) sobre a de gelatina é:", "Cápsulas de HPMC (hidroxipropilmetilcelulose) são alternativas para veganos e pacientes que evitam gelatina animal.", 28, 1, 4 },
                    { 148, "Médio", "O propilenoglicol em formulações semissólidas serve como:", "O propilenoglicol é cossolvente (melhora solubilidade) e umectante (evita ressecamento).", 29, 1, 4 },
                    { 149, "Médio", "A estabilidade de uma emulsão é favorecida por:", "Viscosidade alta da fase contínua retarda a coalescência, e o emulsificante forma filme protetor nas gotas.", 30, 2, 4 },
                    { 150, "Fácil", "Na manipulação, o conceito de FIFO (First In, First Out) garante:", "FIFO: primeiro que entra, primeiro que sai. Evita vencimento de matérias-primas em estoque.", 31, 1, 4 },
                    { 151, "Médio", "A Tween 80 (polissorbato 80) é um tensoativo:", "Tween 80 (polissorbato 80) é tensoativo não iônico amplamente usado como emulsificante e solubilizante.", 32, 2, 4 },
                    { 152, "Médio", "A diferença entre gel hidrofílico e gel lipofílico é:", "Gel hidrofílico usa base aquosa (ex: Carbopol); gel lipofílico (oleogel) usa base oleosa (ex: parafina com polietileno).", 33, 1, 4 },
                    { 153, "Médio", "A celulose microcristalina (CMC) em pós serve como:", "A CMC (Avicel®) é excipiente multifuncional: diluente, desintegrante e aglutinante em compressão direta.", 34, 1, 4 },
                    { 154, "Médio", "O ensaio de endotoxinas bacterianas aplicado a injetáveis usa:", "O teste LAL detecta endotoxinas (lipopolissacarídeos de Gram-negativos) em produtos parenterais.", 35, 1, 4 },
                    { 155, "Fácil", "A filtração esterilizante utiliza membranas com poro de:", "Membranas de 0,22 µm retêm bactérias, sendo usadas na esterilização de soluções termolábeis.", 36, 1, 4 },
                    { 156, "Fácil", "O veículo Ora-Plus® é utilizado como:", "Ora-Plus® é veículo suspensor pré-fabricado, amplamente usado para formulações magistrais pediátricas.", 37, 1, 4 },
                    { 157, "Fácil", "A trituração é uma operação farmacotécnica que visa:", "A trituração (em gral e pistilo) reduz partículas, melhora homogeneidade e facilita dissolução.", 38, 1, 4 },
                    { 158, "Difícil", "A dextrose em formulações liofilizadas atua como:", "Açúcares como dextrose e manitol protegem proteínas durante liofilização e formam cake elegante.", 39, 2, 4 },
                    { 159, "Fácil", "A fotoproteção de formulações fotossensíveis é feita com:", "Frascos âmbar bloqueiam luz UV e visível, protegendo formulações fotossensíveis da degradação.", 40, 1, 4 },
                    { 160, "Fácil", "A validação de processos tem como objetivo:", "Validação: evidência documentada de que o processo reprodutivelmente gera produto conforme especificações.", 1, 0, 5 },
                    { 161, "Médio", "A classificação de salas limpas Grau A (ISO 5) corresponde a:", "Grau A (ISO 5): ambiente com fluxo laminar para operações de máximo risco (envase asséptico).", 2, 1, 5 },
                    { 162, "Fácil", "O teste de dissolução avalia:", "O teste de dissolução mede a taxa e extensão de dissolução do fármaco, predizendo disponibilidade in vivo.", 3, 1, 5 },
                    { 163, "Fácil", "A granulação úmida é realizada para:", "A granulação úmida melhora fluxo, compressibilidade, uniformidade de conteúdo e reduz poeira.", 4, 1, 5 },
                    { 164, "Médio", "A liofilização é um processo de:", "Liofilização: congelamento seguido de sublimação sob vácuo, preservando proteínas e compostos termolábeis.", 5, 1, 5 },
                    { 165, "Fácil", "O teste de friabilidade de comprimidos avalia:", "Friabilidade: perda de massa (%) após rotação em friabilômetro. Limite aceitável: ≤1,0%.", 6, 1, 5 },
                    { 166, "Médio", "O estudo de estabilidade acelerada (zona IVb) utiliza condições de:", "Estabilidade acelerada para zona IVb (clima tropical): 40°C ± 2°C e 75% ± 5% UR por 6 meses.", 7, 2, 5 },
                    { 167, "Fácil", "A compressão direta tem como vantagem principal:", "A compressão direta elimina etapas de granulação e secagem, sendo mais simples, rápida e econômica.", 8, 1, 5 },
                    { 168, "Médio", "O equipamento utilizado para revestimento de comprimidos é:", "Drageadeiras convencionais e de perfuração lateral, além de Wurster (leito fluidizado) para revestimento pelicular.", 9, 1, 5 },
                    { 169, "Fácil", "A BPF/GMP exige que todas as etapas de produção sejam:", "BPF: toda operação deve ser registrada, documentada e rastreável para garantir qualidade e segurança.", 10, 1, 5 },
                    { 170, "Médio", "O Water for Injection (WFI) deve ser produzido por:", "WFI: produzida por destilação ou osmose reversa dupla-passe com monitoramento de endotoxinas (< 0,25 EU/mL).", 11, 1, 5 },
                    { 171, "Fácil", "O teste de desintegração avalia:", "Desintegração: tempo para o comprimido fragmentar-se em partículas menores no meio aquoso.", 12, 0, 5 },
                    { 172, "Fácil", "O IPC (Controle em Processo) inclui a verificação de:", "IPC durante compressão: peso individual, dureza, espessura e desintegração são verificados periodicamente.", 13, 0, 5 },
                    { 173, "Médio", "O polimorfismo de fármacos é relevante porque:", "Polimorfos variam em solubilidade, ponto de fusão e biodisponibilidade; o polimorfo mais estável pode ser menos solúvel.", 14, 1, 5 },
                    { 174, "Médio", "A qualificação de equipamentos segue a sequência:", "Sequência: DQ (Design) → IQ (Instalação) → OQ (Operação) → PQ (Performance/Desempenho).", 15, 1, 5 },
                    { 175, "Médio", "O scale-up de formulações é desafiador porque:", "Variáveis como transferência de calor, cisalhamento e tempo de mistura mudam com o aumento de escala.", 16, 1, 5 },
                    { 176, "Fácil", "O estudo de bioequivalência compara entre genérico e referência:", "Bioequivalência: Cmax, AUC0-t e Tmax são comparados, com ICs de 90% dentro de 80-125%.", 17, 2, 5 },
                    { 177, "Médio", "O excipiente Croscarmelose sódica em comprimidos atua como:", "Croscarmelose é superdesintegrante que absorve água rapidamente, causando inchamento e ruptura do comprimido.", 18, 1, 5 },
                    { 178, "Médio", "Na validação de limpeza, o critério de aceitação visa:", "Validação de limpeza demonstra que resíduos do produto anterior estão abaixo do MACO (Maximum Allowable Carryover).", 19, 1, 5 },
                    { 179, "Médio", "A compactação por rolos (dry granulation) é indicada quando:", "Granulação seca por compactação (slugging ou roller compaction) evita exposição à umidade e calor.", 20, 1, 5 },
                    { 180, "Médio", "O leito fluidizado (Wurster) é utilizado para:", "O sistema Wurster usa fluxo de ar ascendente para fluidizar partículas e aplicar revestimento uniforme.", 21, 1, 5 },
                    { 181, "Fácil", "O registro de medicamento genérico na ANVISA exige:", "Genéricos: equivalência farmacêutica (testes físico-químicos) + bioequivalência in vivo.", 22, 1, 5 },
                    { 182, "Fácil", "A uniformidade de conteúdo verifica:", "Uniformidade de conteúdo: cada comprimido/cápsula deve ter o teor de ativo entre 85-115% (USP).", 23, 1, 5 },
                    { 183, "Médio", "O spray-drying é um processo de:", "Spray-drying: solução/suspensão é atomizada em gotículas que secam instantaneamente com ar quente.", 24, 2, 5 },
                    { 184, "Fácil", "O CAPA (Ações Corretivas e Preventivas) faz parte do:", "CAPA é ferramenta do SGQ que identifica causas-raiz de desvios e implementa ações para evitar recorrência.", 25, 1, 5 },
                    { 185, "Fácil", "A dureza de comprimidos é medida em:", "Dureza: força necessária para quebrar o comprimido diametralmente, expressa em Newtons (N) ou kgf.", 26, 1, 5 },
                    { 186, "Fácil", "Pré-formulação é a etapa que:", "Pré-formulação: investigação de solubilidade, polimorfismo, pKa, estabilidade e compatibilidade com excipientes.", 27, 1, 5 },
                    { 187, "Difícil", "O conceito de PAT (Process Analytical Technology) visa:", "PAT: controle em tempo real de atributos críticos de qualidade durante a produção, reduzindo rejeitos.", 28, 1, 5 },
                    { 188, "Fácil", "A estabilidade de prateleira (shelf life) é o tempo em que:", "Shelf life: período em que o produto mantém qualidade, segurança e eficácia nas condições de armazenamento.", 29, 1, 5 },
                    { 189, "Médio", "O teste de dissolução para formas de liberação prolongada requer:", "Para liberação prolongada: perfil de dissolução com múltiplos pontos (ex: 1h, 2h, 4h, 8h, 12h).", 30, 1, 5 },
                    { 190, "Médio", "A granulação úmida utiliza como líquido de granulação:", "Líquido de granulação: água ou solução de agente ligante (PVP, HPMC) que une partículas em grânulos.", 31, 1, 5 },
                    { 191, "Fácil", "A secagem em estufa de circulação forçada opera por:", "A estufa com circulação forçada de ar quente remove umidade por convecção, secando grânulos e pós.", 32, 1, 5 },
                    { 192, "Fácil", "O blister (embalagem primária) protege comprimidos de:", "Blisters (alumínio/PVC) fornecem barreira contra umidade, luz e contaminação microbiana.", 33, 1, 5 },
                    { 193, "Médio", "A especificação farmacopeica de 'peso médio' para comprimidos tolera variação de:", "Comprimidos ≥250mg: variação de peso ≤±5%; <250mg: ≤±7,5% (FB e USP).", 34, 1, 5 },
                    { 194, "Médio", "A mistura de pós em misturador V-blender é eficiente para:", "O V-blender (misturador em V) é eficiente para pós com granulometria e densidade semelhantes.", 35, 1, 5 },
                    { 195, "Fácil", "A diferença entre medicamento genérico e similar é:", "Genérico: bioequivalente + intercambiável. Similar: mesma molécula, mas pode ter excipientes diferentes e exige testes adicionais.", 36, 1, 5 },
                    { 196, "Fácil", "O desvio de processo na produção farmacêutica deve ser:", "Todo desvio deve ser registrado, investigado quanto à causa-raiz e ter ações corretivas implementadas (CAPA).", 37, 1, 5 },
                    { 197, "Médio", "O fluxo laminar em área asséptica garante:", "O fluxo laminar (unidirecional) mantém ar com contagem de partículas controlada na zona crítica.", 38, 1, 5 },
                    { 198, "Difícil", "O ICH Q8 (Desenvolvimento Farmacêutico) introduziu o conceito de:", "O Design Space define a combinação de variáveis de processo dentro da qual a qualidade é assegurada.", 39, 1, 5 },
                    { 199, "Médio", "A validação concorrente é realizada:", "Validação concorrente: dados coletados durante a fabricação dos primeiros lotes comerciais para demonstrar consistência.", 40, 1, 5 },
                    { 200, "Fácil", "O sistema de dose unitária caracteriza-se por:", "Dose unitária: dispensação individualizada com medicamentos prontos por paciente/dose/horário, reduzindo erros.", 1, 1, 6 },
                    { 201, "Fácil", "A CFT (Comissão de Farmácia e Terapêutica) é responsável por:", "A CFT assessora a seleção e uso racional de medicamentos, elaborando a lista de padronizados do hospital.", 2, 1, 6 },
                    { 202, "Fácil", "A reconciliação medicamentosa deve ser realizada:", "Reconciliação: comparação das medicações do paciente em cada transição para evitar discrepâncias e erros.", 3, 1, 6 },
                    { 203, "Fácil", "Medicamentos de alta vigilância (MAV) são aqueles que:", "MAV (ex: KCl concentrado, insulina, opioides) requerem protocolos adicionais de segurança por seu potencial de dano.", 4, 1, 6 },
                    { 204, "Fácil", "O Antimicrobial Stewardship tem como objetivo:", "O programa de gerenciamento de antimicrobianos visa uso racional, combate à resistência e redução de custos.", 5, 1, 6 },
                    { 205, "Fácil", "A Nutrição Parenteral Total (NPT) é preparada em:", "NPT é preparada assepticamente em capela de fluxo laminar classe 100 (ISO 5), na farmácia hospitalar.", 6, 1, 6 },
                    { 206, "Fácil", "O erro de medicação é definido como:", "Erro de medicação é evitável e pode ocorrer na prescrição, dispensação, administração ou monitoramento.", 7, 1, 6 },
                    { 207, "Fácil", "A prescrição eletrônica reduz erros principalmente de:", "Sistemas eletrônicos eliminam erros de legibilidade e incorporam alertas de dose, alergia e interação.", 8, 1, 6 },
                    { 208, "Fácil", "O Centro de Informação sobre Medicamentos (CIM) fornece:", "O CIM oferece informação imparcial e baseada em evidência para profissionais de saúde.", 9, 1, 6 },
                    { 209, "Médio", "A farmacocinética clínica hospitalar auxilia na:", "A farmacocinética clínica usa níveis séricos (vancomicina, aminoglicosídeos, fenitoína) para ajustar doses individuais.", 10, 1, 6 },
                    { 210, "Fácil", "O sistema de distribuição coletivo caracteriza-se por:", "No sistema coletivo, medicamentos são enviados em estoque para a enfermaria, sem individualização por paciente.", 11, 1, 6 },
                    { 211, "Médio", "A quimioterapia antineoplásica deve ser manipulada em:", "Antineoplásicos são manipulados em CSB classe II B2 com exaustão total, protegendo operador e produto.", 12, 1, 6 },
                    { 212, "Fácil", "A farmácia satélite na UTI tem como vantagem:", "Farmácias satélites descentralizadas na UTI permitem agilidade, monitoramento próximo e redução de tempos de espera.", 13, 1, 6 },
                    { 213, "Médio", "O conceito de 'near miss' em segurança do paciente refere-se a:", "Near miss: incidente que poderia ter causado dano, mas foi interceptado antes de atingir o paciente.", 14, 1, 6 },
                    { 214, "Fácil", "O armazenamento de insulinas no hospital deve ser feito a:", "Insulinas devem ser armazenadas em geladeira (2-8°C); após aberto, o frasco pode ficar em T ambiente por até 28 dias.", 15, 1, 6 },
                    { 215, "Fácil", "Os medicamentos LASA (Look-Alike, Sound-Alike) representam risco por:", "Medicamentos LASA (ex: dobutamina/dopamina) são confundidos por similaridade de nome ou embalagem.", 16, 1, 6 },
                    { 216, "Médio", "O indicador 'taxa de erros de dispensação' mede:", "Taxa de erros de dispensação = (nº erros / nº prescrições dispensadas) × 100, indicador de qualidade do serviço.", 17, 1, 6 },
                    { 217, "Fácil", "A rastreabilidade de medicamentos no hospital permite:", "Rastreabilidade permite localizar qualquer unidade dispensada por lote/validade para recolhimento ou investigação.", 18, 1, 6 },
                    { 218, "Fácil", "A intervenção farmacêutica mais comum em hospital é sobre:", "As intervenções farmacêuticas mais frequentes envolvem ajuste de dose, via, frequência e suspensão de duplicidades.", 19, 1, 6 },
                    { 219, "Médio", "O PGRSS (Plano de Gerenciamento de Resíduos de Serviços de Saúde) classifica resíduos em:", "RDC 222/2018: grupos A (infectantes), B (químicos), C (radioativos), D (comuns) e E (perfurocortantes).", 20, 2, 6 },
                    { 220, "Difícil", "A estabilidade da vancomicina após reconstituição em temperatura ambiente é de aproximadamente:", "Vancomicina reconstituída é estável por 14 dias em geladeira ou 96h em T ambiente (verificar referência local).", 21, 2, 6 },
                    { 221, "Médio", "O fluxo de dispensação de antimicrobianos controlados no hospital deve incluir:", "Antimicrobianos restritos requerem autorização da CCIH e monitoramento de consumo pelo Stewardship.", 22, 1, 6 },
                    { 222, "Médio", "A incompatibilidade entre fármacos em Y (via intravenosa) significa:", "Incompatibilidade em Y ocorre quando fármacos precipitam, turvam ou degradam ao serem infundidos simultaneamente.", 23, 1, 6 },
                    { 223, "Fácil", "O carro de emergência deve conter medicamentos verificados:", "O carro de emergência deve ter checklist diário de verificação de presença, validade e integridade dos medicamentos.", 24, 1, 6 },
                    { 224, "Difícil", "A fracionamento de medicamentos na farmácia hospitalar segue a:", "A RDC 80/2006 regulamenta o fracionamento de medicamentos em farmácias hospitalares e de dispensação.", 25, 1, 6 },
                    { 225, "Médio", "O conceito Just in Time (JIT) na gestão de estoque hospitalar visa:", "JIT: manter estoque mínimo necessário com reposição frequente, reduzindo custos e perdas por vencimento.", 26, 1, 6 },
                    { 226, "Fácil", "A classificação ABC (Pareto) de medicamentos considera:", "Curva ABC: classe A = ~20% dos itens que representam ~80% do custo. Prioriza gestão dos itens de maior impacto.", 27, 1, 6 },
                    { 227, "Fácil", "O farmacêutico clínico na UTI contribui para:", "A presença do farmacêutico clínico na UTI reduz erros, interações, eventos adversos e custos.", 28, 1, 6 },
                    { 228, "Médio", "A compatibilidade de medicamentos em NPT deve ser verificada porque:", "Eletrólitos (cálcio e fosfato) podem precipitar; lipídios podem creaming/cracking se incompatíveis.", 29, 1, 6 },
                    { 229, "Fácil", "O formulário terapêutico hospitalar é:", "O formulário terapêutico reúne monografias dos medicamentos padronizados com indicações, doses e recomendações.", 30, 1, 6 },
                    { 230, "Médio", "Alertas de interação em prescrição eletrônica podem causar 'alert fatigue' quando:", "Alert fatigue: excesso de alertas desnecessários faz profissionais ignorarem todos, inclusive os relevantes.", 31, 1, 6 },
                    { 231, "Fácil", "O antimicrobiano empírico deve ser reavaliado em:", "Reavaliação em 48-72h com resultados de cultura permite de-escalonamento ou ajuste da terapia.", 32, 1, 6 },
                    { 232, "Médio", "A osmolaridade da NPT periférica não deve ultrapassar:", "NPT periférica: osmolaridade ≤900 mOsm/L para evitar flebite. Valores maiores exigem acesso central.", 33, 1, 6 },
                    { 233, "Fácil", "A dose de KCl concentrado (19,1%) é considerada de alta vigilância porque:", "KCl concentrado IV pode causar arritmia e parada cardíaca se administrado rapidamente ou não diluído.", 34, 1, 6 },
                    { 234, "Médio", "O indicador 'número de intervenções farmacêuticas aceitas' mede:", "Taxa de aceitação: (intervenções aceitas / total de intervenções) × 100%, indicador de impacto clínico.", 35, 1, 6 },
                    { 235, "Fácil", "A dispensação por código de barras em dose unitária:", "O código de barras valida automaticamente medicamento, dose e paciente, reduzindo erros de dispensação.", 36, 1, 6 },
                    { 236, "Fácil", "A manipulação de antineoplásicos requer uso de:", "Antineoplásicos são citotóxicos; requerem proteção completa do manipulador e CSB classe II B2.", 37, 1, 6 },
                    { 237, "Médio", "A validação do processo de fracionamento inclui:", "Fracionamento validado: identidade, integridade da embalagem primária, estabilidade e rastreabilidade.", 38, 1, 6 },
                    { 238, "Médio", "O uso off-label em hospital deve ser:", "Uso off-label hospitalar deve ser documentado, justificado por evidência e preferencialmente avaliado pela CFT.", 39, 1, 6 },
                    { 239, "Fácil", "A temperatura de armazenamento para medicamentos termolábeis é:", "Termolábeis (vacinas, insulinas, alguns biológicos) devem ser mantidos em 2°C a 8°C com monitoramento contínuo.", 40, 2, 6 },
                    { 240, "Fácil", "O Método Dáder é utilizado para:", "O Método Dáder é uma ferramenta sistematizada de seguimento farmacoterapêutico desenvolvida pela Universidade de Granada.", 1, 1, 7 },
                    { 241, "Médio", "PRM tipo 5 (Problema Relacionado a Medicamento) refere-se a:", "Na classificação de PRM, o tipo 5 é dose insuficiente (quantitativa) do medicamento necessário.", 2, 2, 7 },
                    { 242, "Médio", "A consulta farmacêutica é regulamentada pela:", "A Resolução CFF nº 585/2013 define as atribuições clínicas do farmacêutico, incluindo a consulta farmacêutica.", 3, 1, 7 },
                    { 243, "Fácil", "MIPs (Medicamentos Isentos de Prescrição) podem ser indicados pelo farmacêutico para:", "MIPs são indicados para condições autolimitadas (cefaleia, azia, gripe) com acompanhamento farmacêutico.", 4, 1, 7 },
                    { 244, "Fácil", "O rastreamento em saúde na farmácia pode incluir:", "Farmácias podem realizar rastreamento de glicemia, PA, colesterol, testes de HIV e hepatites.", 5, 1, 7 },
                    { 245, "Médio", "RNM (Resultado Negativo associado à Medicação) de necessidade ocorre quando:", "RNM de necessidade: problema de saúde não tratado que necessita de medicamento.", 6, 2, 7 },
                    { 246, "Fácil", "A dispensação farmacêutica difere da simples entrega do medicamento por:", "A dispensação é ato profissional que inclui análise da prescrição, orientação e garantia de uso correto.", 7, 1, 7 },
                    { 247, "Fácil", "O SOAP é um método de documentação que significa:", "SOAP: S (queixa do paciente), O (dados objetivos), A (avaliação/PRM), P (plano de cuidado).", 8, 1, 7 },
                    { 248, "Fácil", "A revisão da farmacoterapia é indicada quando:", "A revisão é essencial na polifarmácia para identificar duplicidades, interações, doses inadequadas e medicamentos sem indicação.", 9, 1, 7 },
                    { 249, "Fácil", "A educação em saúde pelo farmacêutico visa:", "O farmacêutico educa sobre uso correto, armazenamento, efeitos esperados, automonitoramento e hábitos saudáveis.", 10, 1, 7 },
                    { 250, "Fácil", "A automedicação responsável pressupõe:", "Automedicação responsável: uso consciente de MIPs para condições autolimitadas, com limite de tempo e orientação.", 11, 1, 7 },
                    { 251, "Médio", "O farmacêutico pode aplicar injetáveis em farmácia conforme:", "A RDC 197/2017 e resoluções dos CRFs regulamentam a aplicação de injetáveis em farmácias comunitárias.", 12, 1, 7 },
                    { 252, "Fácil", "A aferição de pressão arterial na farmácia serve como:", "A aferição na farmácia é rastreamento; valores alterados requerem encaminhamento ao médico.", 13, 1, 7 },
                    { 253, "Fácil", "Testes rápidos em farmácia podem detectar:", "Farmácias podem realizar testes rápidos para HIV, hepatites, sífilis, dengue, glicemia capilar e outros.", 14, 1, 7 },
                    { 254, "Fácil", "A Atenção Farmacêutica foi definida por Hepler e Strand como:", "Hepler & Strand (1990): atenção farmacêutica é a provisão responsável com resultados terapêuticos definidos que melhorem a qualidade de vida.", 15, 1, 7 },
                    { 255, "Fácil", "Na indicação de analgésicos isentos de prescrição, o farmacêutico deve considerar:", "O farmacêutico avalia alergias, uso de outros medicamentos, duração do sintoma e sinais de alarme antes de indicar.", 16, 1, 7 },
                    { 256, "Fácil", "O registro (documentação) de serviços farmacêuticos é importante para:", "A documentação garante comunicação entre profissionais, rastreabilidade, avaliação de resultados e proteção legal.", 17, 1, 7 },
                    { 257, "Médio", "O serviço de Gerenciamento da Terapia Medicamentosa (GTM) inclui:", "GTM: avaliação abrangente de todos os medicamentos, identificação de PRM/RNM, plano e acompanhamento.", 18, 1, 7 },
                    { 258, "Médio", "Na atenção farmacêutica ao idoso, é prioritário avaliar:", "Idosos apresentam maior risco de interações, RAM e uso de MPI (medicamentos potencialmente inapropriados).", 19, 1, 7 },
                    { 259, "Médio", "A Resolução CFF 586/2013 permite ao farmacêutico prescrever:", "A Resolução 586/2013 permite prescrição de MIPs, fitoterápicos, terapias não farmacológicas e medicamentos conforme protocolos e competências.", 20, 2, 7 },
                    { 260, "Médio", "O conceito de 'pharmaceutical care' se diferencia de 'clinical pharmacy' por:", "Pharmaceutical care foca no paciente e seus resultados; clinical pharmacy foca mais no medicamento e aspectos técnicos.", 21, 1, 7 },
                    { 261, "Fácil", "Encaminhamento ao médico deve ocorrer quando:", "Sinais de alarme, cronicidade, gravidade ou necessidade de diagnóstico diferencial requerem encaminhamento médico.", 22, 1, 7 },
                    { 262, "Médio", "A adesão ao tratamento pode ser avaliada por:", "Adesão é avaliada por métodos indiretos (Morisky-Green, contagem) e diretos (dosagem sérica, MEMS).", 23, 1, 7 },
                    { 263, "Fácil", "Na indicação farmacêutica para azia/pirose ocasional, a primeira opção é:", "Para azia ocasional, antiácidos são a primeira opção entre MIPs, com duração limitada e encaminhamento se persistir.", 24, 2, 7 },
                    { 264, "Fácil", "O acompanhamento farmacoterapêutico deve incluir:", "O seguimento farmacoterapêutico avalia os 4 pilares: necessidade, efetividade, segurança e adesão.", 25, 1, 7 },
                    { 265, "Fácil", "A triagem farmacêutica (screening) tem como limitação:", "Rastreamento farmacêutico identifica suspeitas e encaminha; não substitui diagnóstico médico.", 26, 1, 7 },
                    { 266, "Fácil", "O plano de cuidado farmacêutico deve conter:", "O plano define metas (ex: HbA1c < 7%), intervenções, seguimento e indicadores de sucesso.", 27, 1, 7 },
                    { 267, "Fácil", "A indicação do uso de protetor solar pelo farmacêutico é exemplo de:", "Orientar sobre fotoproteção é educação em saúde e promoção da saúde, competência do farmacêutico.", 28, 1, 7 },
                    { 268, "Médio", "A técnica motivacional em atenção farmacêutica visa:", "Entrevista motivacional: abordagem empática que ajuda o paciente a resolver ambivalências e aderir ao tratamento.", 29, 1, 7 },
                    { 269, "Fácil", "O valor de glicemia capilar de jejum ≥ 126 mg/dL na farmácia indica:", "Valores alterados na farmácia são rastreamento; o diagnóstico requer confirmação laboratorial e avaliação médica.", 30, 1, 7 },
                    { 270, "Fácil", "A 'lista de problemas' no acompanhamento farmacoterapêutico inclui:", "A lista de problemas organiza condições de saúde, medicamentos e PRMs/RNMs para priorizar intervenções.", 31, 1, 7 },
                    { 271, "Fácil", "Na dispensação de antibióticos, o farmacêutico deve orientar sobre:", "A orientação completa reduz abandono precoce, resistência bacteriana e problemas de adesão.", 32, 1, 7 },
                    { 272, "Fácil", "O conceito de 'empowerment' do paciente na atenção farmacêutica significa:", "Empoderamento: o paciente informado e capacitado participa das decisões terapêuticas.", 33, 1, 7 },
                    { 273, "Fácil", "A entrevista clínica inicial no acompanhamento deve coletar:", "A entrevista reúne informações essenciais para avaliar a farmacoterapia e identificar problemas.", 34, 1, 7 },
                    { 274, "Fácil", "O encaminhamento interprofissional pelo farmacêutico deve ser:", "O encaminhamento formal garante comunicação clara, com dados clínicos, para continuidade do cuidado.", 35, 1, 7 },
                    { 275, "Médio", "A atuação do farmacêutico na dengue inclui:", "Na dengue: AAS e AINEs são contraindicados pelo risco de sangramento. Hidratação e encaminhamento são essenciais.", 36, 1, 7 },
                    { 276, "Fácil", "O indicador 'número de PRM resolvidos' avalia:", "Conta os PRM identificados e resolvidos, refletindo o impacto clínico do serviço farmacêutico.", 37, 1, 7 },
                    { 277, "Fácil", "Ao identificar uma interação medicamentosa significativa durante a dispensação, o farmacêutico deve:", "Interação significativa: o farmacêutico orienta, documenta, contata o prescritor e sugere alternativa se possível.", 38, 1, 7 },
                    { 278, "Fácil", "A educação continuada do farmacêutico em serviços clínicos é importante porque:", "A evolução constante da terapêutica exige atualização permanente do farmacêutico clínico.", 39, 1, 7 },
                    { 279, "Médio", "O instrumento de Morisky-Green avalia:", "O questionário de Morisky-Green (4 ou 8 itens) é um método indireto validado para avaliar adesão.", 40, 1, 7 },
                    { 280, "Fácil", "A Escala de Naranjo avalia:", "A Escala de Naranjo usa 10 perguntas para classificar a causalidade em definitiva, provável, possível ou duvidosa.", 1, 1, 8 },
                    { 281, "Fácil", "O NOTIVISA é utilizado para:", "NOTIVISA: sistema da ANVISA para receber notificações de eventos adversos, queixas técnicas e intoxicações.", 2, 1, 8 },
                    { 282, "Fácil", "Farmacovigilância é definida pela OMS como:", "A OMS define farmacovigilância como a ciência e atividades de detecção e prevenção de problemas relacionados a medicamentos.", 3, 1, 8 },
                    { 283, "Médio", "RAM tipo B (bizarre) é caracterizada por:", "RAM tipo B são idiossincráticas (ex: reações imunológicas), imprevisíveis, raras e não relacionadas à dose.", 4, 1, 8 },
                    { 284, "Médio", "O Plano de Gestão de Risco deve ser apresentado:", "O PGR acompanha o medicamento desde o registro, identificando riscos conhecidos e potenciais com medidas de minimização.", 5, 1, 8 },
                    { 285, "Fácil", "Um sinal em farmacovigilância é:", "Sinal: dados que sugerem nova associação causal (ou aspecto novo de associação conhecida) entre medicamento e evento.", 6, 1, 8 },
                    { 286, "Fácil", "O Programa Sentinela da ANVISA é formado por:", "A Rede Sentinela é composta por hospitais que monitoram e notificam ativamente eventos adversos, queixas e erros.", 7, 1, 8 },
                    { 287, "Fácil", "A queixa técnica difere do evento adverso porque:", "Queixa técnica: problemas de qualidade do produto (cor, precipitação, rotulagem). Evento adverso: efeito indesejado no paciente.", 8, 1, 8 },
                    { 288, "Médio", "O Centro de Monitorização Internacional de Uppsala (UMC) mantém:", "O UMC/OMS gerencia o VigiBase com mais de 30 milhões de notificações de eventos adversos de todo o mundo.", 9, 1, 8 },
                    { 289, "Fácil", "EAPV (Evento Adverso Pós-Vacinação) é:", "EAPV: qualquer ocorrência médica indesejada após vacinação, podendo ou não ter relação causal com a vacina.", 10, 1, 8 },
                    { 290, "Médio", "A notificação espontânea tem como principal limitação:", "A subnotificação é a principal limitação: estima-se que apenas 5-10% das RAMs são notificadas espontaneamente.", 11, 1, 8 },
                    { 291, "Fácil", "O recall de medicamentos é determinado pela:", "A ANVISA determina o recolhimento quando há risco sanitário comprovado (desvio de qualidade, falsificação).", 12, 1, 8 },
                    { 292, "Fácil", "A desprescrição é o processo de:", "Desprescrição: retirada planejada e supervisionada de medicamentos quando riscos superam benefícios.", 13, 1, 8 },
                    { 293, "Fácil", "Reações adversas de hipersensibilidade a medicamentos são classificadas como tipo:", "Reações de hipersensibilidade (alergia) são RAM tipo B: imprevisíveis, não dose-dependentes, base imunológica.", 14, 1, 8 },
                    { 294, "Fácil", "A atualização de bula com novas informações de segurança é feita por:", "O detentor do registro propõe alterações de bula (novas RAMs, contraindicações), aprovadas pela ANVISA.", 15, 1, 8 },
                    { 295, "Fácil", "A farmacovigilância ativa difere da passiva por:", "Farmacovigilância ativa: busca proativa de RAMs em populações (hospitais sentinela, estudos de coorte).", 16, 1, 8 },
                    { 296, "Fácil", "A classificação de gravidade de RAM inclui:", "RAMs são classificadas em leve (sem tratamento), moderada (requer intervenção), grave (hospitalização/óbito) e fatal.", 17, 1, 8 },
                    { 297, "Médio", "O conceito de 'dechallenge positivo' significa:", "Dechallenge positivo: melhora/resolução da RAM após retirada do fármaco, apoiando a relação causal.", 18, 1, 8 },
                    { 298, "Médio", "'Rechallenge positivo' em farmacovigilância indica:", "Rechallenge positivo: reaparecimento da RAM ao reexpor ao fármaco, forte evidência de causalidade.", 19, 1, 8 },
                    { 299, "Fácil", "O erro de medicação é diferente de RAM porque:", "Erro: falha evitável no processo. RAM: resposta nociva e não intencional em doses normais (pode ser inevitável).", 20, 1, 8 },
                    { 300, "Fácil", "A farmacovigilância de fitoterápicos é necessária porque:", "Fitoterápicos podem causar RAMs (hepatotoxicidade, interações com CYP450) e requerem monitoramento.", 21, 1, 8 },
                    { 301, "Difícil", "A análise de sinal em farmacovigilância utiliza métodos como:", "Métodos quantitativos (PRR, ROR, BCPNN) detectam sinais por desproporcionalidade de notificações no banco de dados.", 22, 1, 8 },
                    { 302, "Fácil", "O formulário de notificação de RAM deve incluir:", "A notificação deve conter dados do paciente, fármaco suspeito (dose, via, datas), descrição da RAM e evolução.", 23, 1, 8 },
                    { 303, "Médio", "A lista de medicamentos sujeitos a monitoramento adicional na UE é identificada por:", "Na Europa, medicamentos sob monitoramento adicional possuem triângulo preto ▼ na bula.", 24, 1, 8 },
                    { 304, "Médio", "O período de washout é relevante em farmacovigilância quando:", "O washout garante eliminação do fármaco anterior, evitando confusão na atribuição causal de eventos.", 25, 1, 8 },
                    { 305, "Fácil", "A subnotificação pode ser reduzida por:", "Formulários simplificados, treinamento, sistemas eletrônicos e cultura não punitiva aumentam notificações.", 26, 1, 8 },
                    { 306, "Fácil", "A farmacovigilância contribui para a saúde pública ao:", "A farmacovigilância identifica riscos novos, promove alterações regulatórias e melhora a segurança do uso.", 27, 1, 8 },
                    { 307, "Médio", "A RAM do tipo C (chronic) está associada a:", "RAM tipo C: relacionada ao uso crônico/cumulativo (ex: nefropatia por AINEs, osteoporose por corticoides).", 28, 1, 8 },
                    { 308, "Difícil", "A disproportionality analysis busca identificar:", "A análise de desproporcionalidade compara frequência observada vs. esperada de pares fármaco-evento.", 29, 1, 8 },
                    { 309, "Fácil", "A farmacovigilância no Brasil é coordenada pela:", "A ANVISA é o órgão coordenador do Sistema Nacional de Farmacovigilância (SINAF) no Brasil.", 30, 1, 8 },
                    { 310, "Médio", "O relatório PSUR (Periodic Safety Update Report) é:", "O PSUR compila dados de segurança pós-comercialização, incluindo RAMs, sinais e reavaliação benefício-risco.", 31, 1, 8 },
                    { 311, "Fácil", "A ficha de notificação do NOTIVISA pode ser preenchida por:", "O NOTIVISA aceita notificações de profissionais de saúde, pacientes e cidadãos.", 32, 1, 8 },
                    { 312, "Médio", "A teratogenicidade como RAM é classificada como tipo:", "Efeitos teratogênicos são RAM tipo D: manifestação tardia, relacionada à exposição em período crítico (gestação).", 33, 3, 8 },
                    { 313, "Médio", "A ISO 31000 aplicada à farmacovigilância trata de:", "A ISO 31000 fornece princípios e diretrizes para gestão de riscos, aplicáveis ao gerenciamento de riscos em farmacovigilância.", 34, 1, 8 },
                    { 314, "Fácil", "A análise de risco-benefício de um medicamento considera:", "A avaliação benefício-risco pondera eficácia e necessidade clínica versus RAMs e riscos potenciais.", 35, 1, 8 },
                    { 315, "Fácil", "O conceito de 'minimização de risco' em farmacovigilância inclui:", "Medidas: programas educacionais, guias para profissionais/pacientes, restrição de prescrição/dispensação, alteração de bula.", 36, 1, 8 },
                    { 316, "Difícil", "A classificação CTCAE é usada para:", "CTCAE (Common Terminology Criteria for Adverse Events): escala de 1 (leve) a 5 (óbito), usada em ensaios oncológicos.", 37, 1, 8 },
                    { 317, "Fácil", "O dever de notificar RAMs é do:", "Profissionais de saúde e a indústria têm obrigação regulatória de notificar RAMs às autoridades.", 38, 1, 8 },
                    { 318, "Médio", "O conceito de 'Safety Signal' exige, para ser validado:", "A validação de sinal requer qualidade e quantidade de notificações, plausibilidade biológica e exclusão de vieses.", 39, 1, 8 },
                    { 319, "Fácil", "A farmacovigilância durante a pandemia de COVID-19 foi essencial para:", "O monitoramento ativo pós-comercialização permitiu detectar RAMs raras (miocardite, trombose) de vacinas COVID.", 40, 1, 8 },
                    { 320, "Fácil", "Em Farmacoepidemiologia, \"DDD\" refere-se a:", "Dose Diária Definida: dose média de manutenção assumida por dia para um fármaco", 1, 0, 9 },
                    { 321, "Médio", "Qual termo corresponde a: Dose Diária Definida: dose média de manutenção assumida por dia para um fármaco", "O termo correto e DDD.", 2, 1, 9 },
                    { 322, "Médio", "Em Farmacoepidemiologia, \"ATC\" refere-se a:", "Sistema de classificação anatômica, terapêutica e química de medicamentos", 3, 1, 9 },
                    { 323, "Difícil", "Qual termo corresponde a: Sistema de classificação anatômica, terapêutica e química de medicamentos", "O termo correto e ATC.", 4, 2, 9 },
                    { 324, "Fácil", "Em Farmacoepidemiologia, \"CONITEC\" refere-se a:", "Comissão Nacional de Incorporação de Tecnologias no SUS", 5, 2, 9 },
                    { 325, "Médio", "Qual termo corresponde a: Comissão Nacional de Incorporação de Tecnologias no SUS", "O termo correto e CONITEC.", 6, 3, 9 },
                    { 326, "Médio", "Em Farmacoepidemiologia, \"Farmacoeconomia\" refere-se a:", "Análise de custos e consequências de medicamentos e terapias", 7, 3, 9 },
                    { 327, "Difícil", "Qual termo corresponde a: Análise de custos e consequências de medicamentos e terapias", "O termo correto e Farmacoeconomia.", 8, 0, 9 },
                    { 328, "Fácil", "Em Farmacoepidemiologia, \"Custo-efetividade\" refere-se a:", "Razão entre custo adicional e benefício clínico adicional de uma intervenção", 9, 0, 9 },
                    { 329, "Médio", "Qual termo corresponde a: Razão entre custo adicional e benefício clínico adicional de uma intervenção", "O termo correto e Custo-efetividade.", 10, 1, 9 },
                    { 330, "Médio", "Em Farmacoepidemiologia, \"QALY\" refere-se a:", "Anos de vida ajustados por qualidade, medida de carga de doença", 11, 1, 9 },
                    { 331, "Difícil", "Qual termo corresponde a: Anos de vida ajustados por qualidade, medida de carga de doença", "O termo correto e QALY.", 12, 2, 9 },
                    { 332, "Fácil", "Em Farmacoepidemiologia, \"Ensaio pragmático\" refere-se a:", "Ensaio clínico que avalia efetividade em contexto real", 13, 2, 9 },
                    { 333, "Médio", "Qual termo corresponde a: Ensaio clínico que avalia efetividade em contexto real", "O termo correto e Ensaio pragmático.", 14, 3, 9 },
                    { 334, "Médio", "Em Farmacoepidemiologia, \"Incidência\" refere-se a:", "Número de novos casos de doença em população em risco em período definido", 15, 3, 9 },
                    { 335, "Difícil", "Qual termo corresponde a: Número de novos casos de doença em população em risco em período definido", "O termo correto e Incidência.", 16, 0, 9 },
                    { 336, "Fácil", "Em Farmacoepidemiologia, \"Prevalência\" refere-se a:", "Proporção de indivíduos com doença em determinado momento", 17, 0, 9 },
                    { 337, "Médio", "Qual termo corresponde a: Proporção de indivíduos com doença em determinado momento", "O termo correto e Prevalência.", 18, 1, 9 },
                    { 338, "Médio", "Em Farmacoepidemiologia, \"Risco relativo\" refere-se a:", "Razão entre incidência em expostos e não expostos", 19, 1, 9 },
                    { 339, "Difícil", "Qual termo corresponde a: Razão entre incidência em expostos e não expostos", "O termo correto e Risco relativo.", 20, 2, 9 },
                    { 340, "Fácil", "Em Farmacoepidemiologia, \"Odds ratio\" refere-se a:", "Razão de chances em estudos caso-controle", 21, 2, 9 },
                    { 341, "Médio", "Qual termo corresponde a: Razão de chances em estudos caso-controle", "O termo correto e Odds ratio.", 22, 3, 9 },
                    { 342, "Médio", "Em Farmacoepidemiologia, \"Coorte prospectiva\" refere-se a:", "Estudo que acompanha expostos e não expostos no tempo para medir desfechos", 23, 3, 9 },
                    { 343, "Difícil", "Qual termo corresponde a: Estudo que acompanha expostos e não expostos no tempo para medir desfechos", "O termo correto e Coorte prospectiva.", 24, 0, 9 },
